// Sigma 3.9 - PingSpoof.java (queue-based delay, ~60 lines)
// Reproduced from actual source
public class PingSpoof extends Module {
  private ArrayList<Packet> packetList = new ArrayList<>();
  private Timer timer = new Timer();

  @EventTarget
  public void onPacket(EventPacket ep) {
    // On outgoing: queue C00PacketKeepAlive, cancel immediate send
    if (ep.isOutgoing() && ep.getPacket() instanceof C00PacketKeepAlive
      && mc.thePlayer.isEntityAlive()) {
      packetList.add(ep.getPacket());
      event.setCancelled(true);
      return;
    }
    // On incoming: capture keepalive ID for response
    if (ep.isIncoming() && ep.getPacket() instanceof S00PacketKeepAlive) {
      S00PacketKeepAlive s00 = (S00PacketKeepAlive) ep.getPacket();
      lastKey = s00.func_149134_c(); // store the key
    }
  }

  @EventTarget
  public void onTick(EventTick event) {
    // Release queued packets after configured delay
    if (timer.delay(1000 * waitSeconds) && !packetList.isEmpty()) {
      for (Packet p : packetList) {
        mc.thePlayer.sendQueue.getNetworkManager()
          .sendPacketNoEvent(p);
      }
      // Also send a fake keepalive with large key to confuse anticheat
      mc.thePlayer.sendQueue.getNetworkManager()
        .sendPacketNoEvent(new C00PacketKeepAlive(10000));
      packetList.clear();
    }
  }
}

// Tenacity 5.1 - Disabler.java (Watchdog mode, lines 145-165)
// Reproduced from actual source: https://github.com/TenacityMC/Tenacity
@Subscribe
public void onPacketSend(PacketEvent event) {
  if (mc.thePlayer == null) return;
  Packet<?> packet = event.getPacket();
  String mode = disablerMode.getSelectedOption();

  if (mode.equals("Watchdog")) {
    // Queue C0FPacketConfirmTransaction + C00PacketKeepAlive for 350ms
    // Watchdog uses a sliding window of ~500ms to correlate client actions.
    // By withholding all C0F and C00 for 350ms and then flushing them,
    // Watchdog's window desyncs and stops flagging movement.
    if (!timer.hasTimeElapsed(350)) {
      if (packet instanceof C0FPacketConfirmTransaction
        || packet instanceof C00PacketKeepAlive) {
        event.cancel();
        watchdogC0FC00Packets.add(packet);
      }
    } else if (!watchdogC0FC00Packets.isEmpty()) {
      watchdogC0FC00Packets.forEach(PacketUtils::sendPacketNoEvent);
      watchdogC0FC00Packets.clear();
    }
  } else if (mode.equals("Verus")) {
    // Verus: cancel ALL transaction + keepalive
    if (packet instanceof C0FPacketConfirmTransaction
      || packet instanceof C00PacketKeepAlive) {
      event.cancel();
    }
  } else if (mode.equals("MMC")) {
    // Minemen Club: cancel C0F+C00, store in separate queue
    if (packet instanceof C0FPacketConfirmTransaction
      || packet instanceof C00PacketKeepAlive) {
      event.cancel();
      packets.add(packet);
    }
  }
}

// Memeware 7.3 - Disabler.java (Mineplex + Faithful modes)
// Reproduced from actual source
// Mineplex: randomly shift keepalive key to bypass anticheat
if (isMode("Mineplex Combat")) {
  if (event.getPacket() instanceof C00PacketKeepAlive) {
    C00PacketKeepAlive packetKeepAlive =
      (C00PacketKeepAlive) event.getPacket();
    // Subtract random 3-127 from the key value.
    // The server expects a specific key but Mineplex's anticheat
    // accepts a range around the expected value.
    packetKeepAlive.key -= RandomUtils.nextInt(3, 128);
  }
}

// Faithful: shift keepalive key by exactly 31
if (isMode("Faithful Movement")) {
  if (mc.thePlayer != null && event.getPacket() instanceof C00PacketKeepAlive) {
    C00PacketKeepAlive packetKeepAlive =
      (C00PacketKeepAlive) event.getPacket();
    packetKeepAlive.key -= 31;
  }
}

// Jigsaw 0.24 - DialUpPing.java
if (packet instanceof C00PacketKeepAlive) {
  if (tries != 0) { packet.cancel(); }  // drop this keepalive
  tries++;
  if (tries > 149) tries = 0;
}

// November 0.2 - PingSpoof.java (TreeMap queue)
// Reproduced from actual source
private final TreeMap<Long, Packet> packets = new TreeMap<>();

@EventTarget
public void onSend(EventSendPacket event) {
  Packet p = event.getPacket();
  if (p instanceof C0FPacketConfirmTransaction
    || p instanceof C00PacketKeepAlive) {
    // Schedule for future delivery
    long releaseAt = System.currentTimeMillis()
      + (long) this.ping.getValue();
    this.packets.put(releaseAt, p);
    event.setCancelled(true);
  }
}

@EventTarget
public void onTick(EventTick event) {
  // Release all packets whose time has come
  long now = System.currentTimeMillis();
  while (!this.packets.isEmpty()
    && this.packets.firstKey() <= now) {
    Packet p = this.packets.pollFirstEntry().getValue();
    this.sendPacket(p);
  }
}
